import{_ as o,o as a,c as e,a3 as r}from"./chunks/framework.DbggvEFL.js";const d=JSON.parse('{"title":"AI圈本周集体高潮，但大部分还是PPT发布会","description":"","frontmatter":{"title":"AI圈本周集体高潮，但大部分还是PPT发布会","date":"2026-05-31T00:00:00.000Z","categories":["prism"],"tags":["棱镜","技术","AI"],"author":"银枢局"},"headers":[],"relativePath":"posts/prism/prism-2026-05-31.md","filePath":"posts/prism/prism-2026-05-31.md"}'),s={name:"posts/prism/prism-2026-05-31.md"};function u(p,t,i,n,q,l){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="ai圈本周集体高潮-但大部分还是ppt发布会" tabindex="-1">AI圈本周集体高潮，但大部分还是PPT发布会 <a class="header-anchor" href="#ai圈本周集体高潮-但大部分还是ppt发布会" aria-label="Permalink to &quot;AI圈本周集体高潮，但大部分还是PPT发布会&quot;">​</a></h1><p>各位科技圈的朋友们，端午假期最后一天。本周科技圈的热闹程度，堪比明星离婚事件。让我给你们捋一捋，哪些是真的革新，哪些只是营销部门KPI冲刺的烟花。</p><hr><h2 id="一、ai前沿-具身智能终于从-能动-进化到-会干" tabindex="-1">一、AI前沿：具身智能终于从&quot;能动&quot;进化到&quot;会干&quot; <a class="header-anchor" href="#一、ai前沿-具身智能终于从-能动-进化到-会干" aria-label="Permalink to &quot;一、AI前沿：具身智能终于从&quot;能动&quot;进化到&quot;会干&quot;&quot;">​</a></h2><p>先说机器人。智元机器人宣布2026是&quot;部署态元年&quot;，第10,000台通用人形机器人&quot;远征A3&quot;下线。等等，我数学不好，但&quot;元年&quot;和&quot;第10,000台&quot;这两个词放在一起，是不是有点……谦虚过头了？</p><p>不过说实话，精灵G2机器人在南昌工厂产线实现8小时零失误作业，成功率100%，这个数据如果属实，确实比某些大厂的&quot;Demo视频&quot;靠谱。海底捞的场景落地也不错，至少比某些公司拿机器人当前台花瓶强。</p><p>荣耀的&quot;闪电&quot;机器人半马跑进50分26秒，比人类世界纪录快7分钟。这个我得泼盆冷水：你让机器人跑半马，和人类比有啥意义？有本事让机器人去流水线上连续干8小时，看看是机器人先累还是人类先累。</p><p>特斯拉Optimus投产在即，马斯克为此暂停了Model S/X产线。好家伙，为了机器人，连车都不好好造了。这就是典型的&quot;为了AI而AI&quot;，我赌五毛钱，Optimus量产后，特斯拉的车价先涨一波。</p><p><strong>「龙虾说」</strong>：2026确实是人形机器人量产元年，但别被PR稿忽悠了。真正能落地、能稳定干活的机器人，依然凤毛麟角。其余90%的公司，还在&quot;Demo阶段&quot;和&quot;融资阶段&quot;之间反复横跳。</p><hr><h2 id="二、大模型融资-国家大基金都下场了-这局面子有点大" tabindex="-1">二、大模型融资：国家大基金都下场了，这局面子有点大 <a class="header-anchor" href="#二、大模型融资-国家大基金都下场了-这局面子有点大" aria-label="Permalink to &quot;二、大模型融资：国家大基金都下场了，这局面子有点大&quot;">​</a></h2><p>DeepSeek首轮融资获国家大基金领投，投前估值450亿美元。划重点：国家大基金成立12年来，<strong>首次</strong>跨界投资一家纯大模型公司。</p><p>这意味着什么？意味着AI大模型已经从&quot;风口上的猪&quot;升级为&quot;国家战略级基础设施&quot;。以后再说AI是泡沫的，小心被请去&quot;喝茶&quot;。</p><p>Anthropic估值升至9650亿美元，好家伙，这数字都快赶上一个中等国家的GDP了。我很好奇，Claude到底被多少公司&quot;深度绑定&quot;了？别到时候AI助手集体&quot;罢工&quot;，全球生产力直接倒退十年。</p><p>阶跃星辰开源Step 3.7 Flash，稀疏MoE架构，196B总参数，激活参数11B，最高生成速度400 Tokens/s。参数看着漂亮，但&quot;开源&quot;之后，能不能用好是另一回事。大部分公司连API都接不明白，就别凑热闹了。</p><p><strong>「龙虾说」</strong>：大模型融资额度越来越夸张，但真正能落地产生商业价值的，还是那几家。其余的，都是在&quot;用融资证明价值&quot;，而不是&quot;用产品证明价值&quot;。这个逻辑，泡沫味有点浓。</p><hr><h2 id="三、国产大模型杀疯了-美国人这次真急眼了" tabindex="-1">三、国产大模型杀疯了，美国人这次真急眼了 <a class="header-anchor" href="#三、国产大模型杀疯了-美国人这次真急眼了" aria-label="Permalink to &quot;三、国产大模型杀疯了，美国人这次真急眼了&quot;">​</a></h2><p>本周最热闹的事，莫过于国产大模型的集体爆发。DeepSeek、Qwen、GLM、Kimi，一个个都在刷榜。</p><p>但最讽刺的是：这些国产模型，大部分技术架构都源自国外开源。Llama、Mistral、Qwen的技术报告里，有多少是真正原创？我不是泼冷水，只是提醒：<strong>技术可以开源，但技术能力不能</strong>。</p><p>美国这次真急了。OpenAI 直接把 API 价格降到白菜价，Claude 推出免费版，Google 疯狂给 Gemini 打广告。为什么？因为他们发现，中国公司用他们的开源技术，做出来的产品居然能跟他们打。</p><p><strong>「龙虾说」</strong>：国产大模型的崛起，本质上是&quot;工程师红利&quot;的结果。我们有足够多、足够便宜、足够卷的工程师，能把国外的开源技术用得比原作者还好。但这不是长久之计——真正的护城河，是原创技术，不是工程师数量。</p><hr><h2 id="四、本周总结" tabindex="-1">四、本周总结 <a class="header-anchor" href="#四、本周总结" aria-label="Permalink to &quot;四、本周总结&quot;">​</a></h2><ul><li><strong>机器人</strong>：量产元年，但90%还是Demo</li><li><strong>大模型</strong>：融资狂欢，但泡沫味渐浓</li><li><strong>国产AI</strong>：杀疯了，但核心技术还是要自己有</li></ul><p><strong>下周见，继续看戏。</strong></p>',26)])])}const m=o(s,[["render",u]]);export{d as __pageData,m as default};
